322	    if (std.ascii.eqlIgnoreCase(value, "on") or
323	        std.ascii.eqlIgnoreCase(value, "yes") or
324	        std.mem.eql(u8, value, "1"))
325	    {
326	        return true;
327	    }
328	    if (std.ascii.eqlIgnoreCase(value, "off") or
329	        std.ascii.eqlIgnoreCase(value, "no") or
