337	fn parsePrefixValue(value: []const u8) ?u21 {
338	    const parsed = key_string.stringToKey(value) orelse return null;
339	    if (parsed.mods.meta or parsed.mods.shift) return null;
340	    if (!parsed.mods.ctrl) return parsed.key;
341	
342	    if (parsed.key == ' ') return 0;
343	    if (parsed.key >= 'a' and parsed.key <= 'z') return parsed.key - 'a' + 1;
344	    if (parsed.key >= 'A' and parsed.key <= 'Z') return parsed.key - 'A' + 1;
345	    return null;
346	}
