388	fn extractCopySelection(alloc: std.mem.Allocator, pane_state: anytype, state: *const copy_mod.CopyState) ![]u8 {
389	    const grid = &pane_state.screen.grid;
390	    const total_lines = grid.hsize + grid.rows;
391	    if (total_lines == 0) return try alloc.dupe(u8, "");
392	
393	    const start_y = @min(state.sel_start_y, state.cy);
394	    const end_y = @min(@max(state.sel_start_y, state.cy), total_lines - 1);
395	    const start_x = @min(state.sel_start_x, state.cx);
396	    const end_x = @max(state.sel_start_x, state.cx);
397	
398	    var out: std.ArrayListAligned(u8, null) = .empty;
399	    errdefer out.deinit(alloc);
400	
401	    var y = start_y;
402	    while (y <= end_y) : (y += 1) {
403	        const line_text = if (state.mode == .visual_line)
404	            try extractGridLineSlice(alloc, pane_state, y, 0, grid.cols -| 1)
405	        else if (start_y == end_y)
406	            try extractGridLineSlice(alloc, pane_state, y, start_x, end_x)
407	        else if (y == start_y)
408	            try extractGridLineSlice(alloc, pane_state, y, start_x, grid.cols -| 1)
409	        else if (y == end_y)
410	            try extractGridLineSlice(alloc, pane_state, y, 0, end_x)
411	        else
412	            try extractGridLineSlice(alloc, pane_state, y, 0, grid.cols -| 1);
413	        defer alloc.free(line_text);
414	
415	        try out.appendSlice(alloc, line_text);
416	        if (y != end_y) try out.append(alloc, '\n');
417	    }
418	
419	    return try out.toOwnedSlice(alloc);
420	}
