422	fn handleCopyModeAction(ctx: *Context, pane: *Pane, pane_state: anytype, action: copy_mod.CopyAction) CmdError!void {
423	    switch (action) {
424	        .move_cursor, .start_selection, .search_next, .search_prev => {},
425	        .scroll_up => if (pane.copy_state) |*state| {
426	            if (state.cy > 0) state.cy -= 1;
427	        },
428	        .scroll_down => if (pane.copy_state) |*state| {
429	            const max_y = pane_state.screen.grid.hsize + pane_state.screen.grid.rows -| 1;
430	            state.cy = @min(max_y, state.cy + 1);
431	        },
432	        .page_up => if (pane.copy_state) |*state| {
433	            const step = pane_state.screen.grid.rows;
434	            state.cy = state.cy -| step;
435	        },
436	        .page_down => if (pane.copy_state) |*state| {
437	            const step = pane_state.screen.grid.rows;
438	            const max_y = pane_state.screen.grid.hsize + pane_state.screen.grid.rows -| 1;
439	            state.cy = @min(max_y, state.cy + step);
440	        },
441	        .cancel => pane.copy_state = null,
442	        .copy_selection => {
443	            const state = pane.copy_state orelse return;
444	            const text = extractCopySelection(ctx.allocator, pane_state, &state) catch return CmdError.CommandFailed;
445	            defer ctx.allocator.free(text);
446	            ctx.server.paste_stack.push(text, null) catch return CmdError.OutOfMemory;
447	            pane.copy_state = null;
448	        },
449	    }
450	}
