452	fn handleCopyModeKey(ctx: *Context, pane: *Pane, key_arg: []const u8) CmdError!bool {
453	    const pane_state = ctx.server.session_loop.getPane(pane.id) orelse return false;
454	    var handled = false;
455	
456	    if (key_string.stringToKey(key_arg)) |result| {
457	        if (pane.copy_state) |*state| {
458	            const mods: copy_mod.Modifiers = .{
459	                .ctrl = result.mods.ctrl,
460	                .meta = result.mods.meta,
461	                .shift = result.mods.shift,
462	            };
463	            if (state.handleKey(result.key, mods)) |action| {
464	                try handleCopyModeAction(ctx, pane, pane_state, action);
465	            }
466	            handled = true;
467	        }
468	    } else if (pane.copy_state) |*state| {
469	        for (key_arg) |byte| {
470	            if (state.handleKey(byte, .{})) |action| {
471	                try handleCopyModeAction(ctx, pane, pane_state, action);
472	            }
473	        }
474	        handled = true;
475	    }
476	
477	    return handled;
478	}
