488	fn executeCommandString(ctx: *Context, command_text: []const u8) CmdError!void {
489	    const registry = ctx.registry orelse return CmdError.CommandFailed;
490	    if (command_text.len == 0) return;
491	
492	    var parser = config_parser.ConfigParser.init(ctx.allocator, command_text);
493	    var commands = parser.parseAll() catch return CmdError.CommandFailed;
494	    defer {
495	        for (commands.items) |*command| command.deinit(ctx.allocator);
496	        commands.deinit(ctx.allocator);
497	    }
498	    if (commands.items.len == 0) return CmdError.InvalidArgs;
499	
500	    for (commands.items) |*command| {
501	        try registry.executeParsed(ctx, command);
502	    }
503	}
