505	fn executePromptBuffer(ctx: *Context, pane: *Pane) CmdError!void {
506	    const prompt_state = pane.prompt_state orelse return;
507	    const command_text = prompt_state.buffer[0..prompt_state.len];
508	
509	    pane.prompt_state = null;
510	    try executeCommandString(ctx, command_text);
511	}
