4	/// Environment variable store.
5	/// Manages a set of key=value pairs, with support for inheritance
6	/// from the system environment and per-session overrides.
7	pub const Environ = struct {
8	    vars: std.StringHashMap(Entry),
9	
10	    pub const Entry = struct {
11	        value: ?[]const u8,
12	        hidden: bool,
13	    };
14	
15	    pub fn init(alloc: Allocator) Environ {
16	        return .{
17	            .vars = std.StringHashMap(Entry).init(alloc),
18	        };
19	    }
20	
21	    pub fn deinit(self: *Environ) void {
22	        const alloc = self.vars.allocator;
23	        var iter = self.vars.iterator();
24	        while (iter.next()) |entry| {
25	            alloc.free(entry.key_ptr.*);
26	            if (entry.value_ptr.value) |v| {
27	                alloc.free(v);
28	            }
29	        }
30	        self.vars.deinit();
31	    }
32	
33	    /// Set a variable. Overwrites if it already exists.
34	    pub fn set(self: *Environ, key: []const u8, value: []const u8) !void {
35	        const alloc = self.vars.allocator;
36	        const owned_key = try alloc.dupe(u8, key);
37	        errdefer alloc.free(owned_key);
38	        const owned_val = try alloc.dupe(u8, value);
39	        errdefer alloc.free(owned_val);
40	
41	        const result = try self.vars.getOrPut(owned_key);
42	        if (result.found_existing) {
43	            alloc.free(result.key_ptr.*);
44	            if (result.value_ptr.value) |old_val| {
45	                alloc.free(old_val);
