    var env = Environ.init(std.testing.allocator);
    defer env.deinit();
    try env.set("FOO", "bar");
    try std.testing.expectEqualStrings("bar", env.get("FOO").?);
}

test "unset" {
    var env = Environ.init(std.testing.allocator);
    defer env.deinit();
    try env.set("FOO", "bar");
    try env.unset("FOO");
    try std.testing.expect(env.get("FOO") == null);
}

